  1→import { readdir, readFile, stat } from "node:fs/promises";
  2→import { homedir } from "node:os";
  3→import { dirname, join } from "node:path";
  4→import type { IngestSessionInput } from "@rudel/api-routes";
  5→import {
  6→	type Ingestor,
  7→	ingestRudelClaudeSessions,
  8→	type RudelClaudeSessionsRow,
  9→} from "@rudel/ch-schema/generated";
 10→import type {
 11→	AgentAdapter,
 12→	IngestContext,
 13→	ScannedProject,
 14→	SessionFile,
 15→	UploadContext,
 16→} from "../../types.js";
 17→import {
 18→	readFileWithRetry,
 19→	toClickHouseDateTime,
 20→	toDisplayPath,
 21→} from "../../utils.js";
 22→import {
 23→	addHook,
 24→	getClaudeSettingsPath,
 25→	isHookEnabled,
 26→	removeHook,
 27→} from "./settings.js";
 28→
 29→const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");
 30→
 31→// ── Exported utilities ──
 32→
 33→export function encodeProjectPath(projectPath: string): string {
 34→	return projectPath.replace(/\//g, "-");
 35→}
 36→
 37→export async function decodeProjectPath(encodedDir: string): Promise<string> {
 38→	const parts = encodedDir.replace(/^-/, "").split("-");
 39→
 40→	async function findPath(
 41→		partIndex: number,
 42→		currentPath: string,
 43→	): Promise<string | null> {
 44→		if (partIndex >= parts.length) {
 45→			try {
 46→				await stat(currentPath);
 47→				return currentPath;
 48→			} catch {
 49→				return null;
 50→			}
 51→		}
 52→
 53→		for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
 54→			const segment = parts.slice(partIndex, endIndex).join("-");
 55→			const testPath = currentPath
 56→				? `${currentPath}/${segment}`
 57→				: `/${segment}`;
 58→
 59→			try {
 60→				await stat(testPath);
 61→				if (endIndex === parts.length) {
 62→					return testPath;
 63→				}
 64→				const result = await findPath(endIndex, testPath);
 65→				if (result) {
 66→					return result;
 67→				}
 68→			} catch {
 69→				// Path doesn't exist, try shorter segment
 70→			}
 71→		}
 72→
 73→		return null;
 74→	}
 75→
 76→	const result = await findPath(0, "");
 77→	if (result) {
 78→		return result;
 79→	}
 80→
 81→	return `/${parts.join("/")}`;
 82→}
 83→
 84→export function extractAgentIds(sessionContent: string): string[] {
 85→	const agentIds = new Set<string>();
 86→
 87→	for (const line of sessionContent.split("\n")) {
 88→		if (!line.trim()) continue;
 89→
 90→		try {
 91→			const entry = JSON.parse(line);
 92→			if (entry.toolUseResult?.agentId) {
 93→				agentIds.add(entry.toolUseResult.agentId);
 94→			}
 95→		} catch {
 96→			// Skip malformed lines
 97→		}
 98→	}
 99→
100→	return Array.from(agentIds);
101→}
102→
103→interface SubagentFile {
104→	agentId: string;
105→	content: string;
106→}
107→
108→export async function readSubagentFiles(
109→	sessionDir: string,
110→	agentIds: string[],
111→	sessionId?: string,
112→): Promise<SubagentFile[]> {
113→	const subagents: SubagentFile[] = [];
114→
115→	for (const agentId of agentIds) {
116→		const possiblePaths = [
117→			join(sessionDir, `agent-${agentId}.jsonl`),
118→			...(sessionId
119→				? [join(sessionDir, sessionId, "subagents", `agent-${agentId}.jsonl`)]
120→				: []),
121→		];
122→
123→		for (const agentPath of possiblePaths) {
124→			try {
125→				const content = await readFile(agentPath, "utf-8");
126→				subagents.push({ agentId, content });
127→				break;
128→			} catch {
129→				// Try next path
130→			}
131→		}
132→	}
133→
134→	return subagents;
135→}
136→
137→// ── Adapter ──
138→
139→class ClaudeCodeAdapter implements AgentAdapter {
140→	name = "Claude Code";
141→	source = "claude_code" as const;
142→	rawTableName = "rudel.claude_sessions";
143→
144→	getSessionsBaseDir(): string {
145→		return SESSIONS_BASE_DIR;
146→	}
147→
148→	async findProjectSessions(projectPath: string): Promise<SessionFile[]> {
149→		const encoded = encodeProjectPath(projectPath);
150→		const sessionDir = join(SESSIONS_BASE_DIR, encoded);
151→
152→		const files = await this.listSessionFiles(sessionDir, projectPath);
153→		if (files.length > 0) return files;
154→
155→		return this.findByDecoding(projectPath);
156→	}
157→
158→	async scanAllSessions(): Promise<ScannedProject[]> {
159→		let projectDirs: string[];
160→		try {
