const sql = fs.readFileSync(\"chx/migrations/20260303160252_auto.sql\", \"utf8\");

// Split on \"-- operation:\" markers
const parts = sql.split(/(?=-- operation:)/);
for (const part of parts) {
  // Skip comment-only or empty parts
  const lines = part.split(\"\n\").filter(l => !l.startsWith(\"--\") && l.trim());
  const stmt = lines.join(\"\n\").trim();
  if (!stmt) continue;

  // Remove trailing semicolons
  const clean = stmt.replace(/;\s*$/, \"\");
  console.log(\"=== Executing:\", clean.substring(0, 80), \"...\");
  try {
    execSync(\`bunx chcli -q \"\${clean}\" -F json\`, { stdio: \"inherit\", env: process.env });
    console.log(\"=== OK\");
  } catch(e) {
    console.error(\"=== FAILED\");
    process.exit(1);
  }
}
"
