input.content:
import { readFileSync } from "fs";
import { execSync } from "child_process";

const file = process.argv[2];
if (!file) {
  console.error("Usage: bun scripts/apply-migration.ts <migration-file>");
  process.exit(1);
}

const sql = readFileSync(file, "utf8");

// Split on "-- operation:" markers
const parts = sql.split(/(?=-- operation:)/);

for (const part of parts) {
  const operationMatch = part.match(/^-- operation: (.+)/);
  const lines = part.split("\n").filter(l => !l.startsWith("--") && l.trim());
  const stmt = lines.join("\n").trim().replace(/;\s*$/, "");
  if (!stmt) continue;

  const label = operationMatch ? operationMatch[1] : stmt.substring(0, 60);
  console.log(`\n=== ${label} ===`);

  // Write statement to a temp file to avoid shell escaping issues
  const tmpFile = `/tmp/chkit-stmt-${Date.now()}.sql`;
  require("fs").writeFileSync(tmpFile, stmt);

  try {
    execSync(`bunx chcli -f "${tmpFile}" -F json`, { stdio: "inherit" });
    console.log("OK");
  } catch (e) {
    console.error("FAILED");
    require("fs").unlinkSync(tmpFile);
    process.exit(1);
  }

  require("fs").unlinkSync(tmpFile);

  // Small delay for ClickHouse Cloud propagation
  Bun.sleepSync(2000);
}

console.log("\n=== All statements applied successfully ===");

